package main

import (
    "fmt"
    "net/http"
    "time"
)

// ---- Handler functions ----
func helloHandler(w http.ResponseWriter, r *http.Request) {
    fmt.Fprintf(w, "Hello, Player!")
}

func healthHandler(w http.ResponseWriter, r *http.Request) {
    w.Header().Set("Content-Type", "application/json")
    fmt.Fprintf(w, `{"status": "ok", "time": "%s"}`, time.Now().Format(time.RFC3339))
}

func playerHandler(w http.ResponseWriter, r *http.Request) {
    name := r.URL.Query().Get("name")
    if name == "" {
        name = "Hero"
    }

    w.Header().Set("Content-Type", "application/json")
    fmt.Fprintf(w, `{"name": "%s", "health": 100, "level": 1}`, name)
}

func gameHandler(w http.ResponseWriter, r *http.Request) {
    // ---- Method handling ----
    switch r.Method {
    case "GET":
        w.Header().Set("Content-Type", "application/json")
        fmt.Fprintf(w, `{"method": "GET", "message": "Fetching game state"}`)
    case "POST":
        w.Header().Set("Content-Type", "application/json")
        fmt.Fprintf(w, `{"method": "POST", "message": "Creating game state"}`)
    case "PUT":
        w.Header().Set("Content-Type", "application/json")
        fmt.Fprintf(w, `{"method": "PUT", "message": "Updating game state"}`)
    case "DELETE":
        w.Header().Set("Content-Type", "application/json")
        fmt.Fprintf(w, `{"method": "DELETE", "message": "Deleting game state"}`)
    default:
        http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
    }
}

func middleware(next http.HandlerFunc) http.HandlerFunc {
    return func(w http.ResponseWriter, r *http.Request) {
        fmt.Printf("[%s] %s %s\n", time.Now().Format("15:04:05"), r.Method, r.URL.Path)
        next(w, r)
    }
}

func main() {
    // ---- Register routes ----
    http.HandleFunc("/", middleware(helloHandler))
    http.HandleFunc("/health", middleware(healthHandler))
    http.HandleFunc("/player", middleware(playerHandler))
    http.HandleFunc("/game", middleware(gameHandler))

    // ---- Serve static files ----
    // http.Handle("/static/", http.StripPrefix("/static/", http.FileServer(http.Dir("./static"))))

    // ---- Start server ----
    fmt.Println("Server starting on :8080")
    fmt.Println("Available routes:")
    fmt.Println("  GET /")
    fmt.Println("  GET /health")
    fmt.Println("  GET /player?name=Hero")
    fmt.Println("  GET /game")
    fmt.Println("  POST /game")
    fmt.Println("  PUT /game")
    fmt.Println("  DELETE /game")

    // ---- Server with custom settings ----
    server := &http.Server{
        Addr:         ":8080",
        Handler:      nil, // DefaultServeMux
        ReadTimeout:  5 * time.Second,
        WriteTimeout: 10 * time.Second,
    }

    err := server.ListenAndServe()
    if err != nil {
        fmt.Println("Error:", err)
    }
}

// ---- Run with ----
